    protected override void OnAfterRender(bool firstRender)
    {
        if (!Context.Multiple || !GroupSelect) return;
        // Aggregation also ignores disabled descendants — they aren't selectable so they
        // shouldn't count towards "all" being checked. Mirror ToggleGroupSelection's
        // search-scope so the tri-state reflects "all visible matches" while filtering.
        var values = (HasActiveSearch
            ? _groupContext.VisibleSelectableDescendantValues
            : _groupContext.SelectableDescendantValues).ToList();
        var all = values.Count > 0 && values.All(v => Context.Values?.Contains(v) == true);
        var any = values.Any(v => Context.Values?.Contains(v) == true);
        if (all != _allSelected || any != _anySelected)
        {
            _allSelected = all;
            _anySelected = any;
            InvokeAsync(StateHasChanged);
        }
    }

    public void Dispose() => ParentGroup?.UnregisterChild(_groupContext);

    /// <summary>
    /// Cascaded to a group's descendants. SelectItems report their value + current
    /// search-visibility + disabled state here; nested groups register themselves so
    /// empty-hiding and group selection aggregate across multiple levels. Exposes
    /// <see cref="LabelId"/> for <c>SelectLabel</c> and <see cref="IsExpanded"/> for
    /// descendants that need to react to collapse (SelectItem uses it to drop out of
    /// keyboard navigation when its group is collapsed).
    /// </summary>
    public sealed class SelectGroupContext
    {
        private readonly Action _onChanged;
        private readonly Dictionary<string, (string Value, bool Visible, bool Disabled)> _items = new();
        private readonly List<SelectGroupContext> _childGroups = new();
        private readonly SelectGroupContext? _parent;

        public SelectGroupContext(string labelId, int depth, Action onChanged, bool isExpanded, SelectGroupContext? parent)
        {
            LabelId = labelId;
            Depth = depth;
            IsExpanded = isExpanded;
            _parent = parent;
            _onChanged = onChanged;
        }

        /// <summary>Stable id used by <c>SelectLabel</c> for <c>aria-labelledby</c>.</summary>
        public string LabelId { get; }

        public int Depth { get; }

        /// <summary>True when this group's own header is expanded.</summary>
        public bool IsExpanded { get; private set; }

        /// <summary>True only when this group AND every ancestor are expanded. Items consult
        /// this (not <see cref="IsExpanded"/>) so a collapsed outer group correctly hides
        /// inner items even if the inner group is locally expanded — multi-level collapse
        /// would otherwise leak nav focus into CSS-hidden subtrees.</summary>
        public bool EffectiveIsExpanded => IsExpanded && (_parent?.EffectiveIsExpanded ?? true);

        public void SetExpanded(bool value)
        {
            if (IsExpanded == value) return;
            IsExpanded = value;
            _onChanged();
        }

        public void RegisterItem(string id, string value, bool visible, bool disabled)
        {
            // Only notify on real change — SelectItem calls this on every parameter set.
            if (_items.TryGetValue(id, out var existing)
                && existing.Value == value && existing.Visible == visible && existing.Disabled == disabled)
                return;
            _items[id] = (value, visible, disabled);
            _onChanged();
        }

        public void UnregisterItem(string id)
        {
            if (_items.Remove(id)) _onChanged();
        }

        public void RegisterChild(SelectGroupContext child)
        {
            if (!_childGroups.Contains(child)) _childGroups.Add(child);
            _onChanged();
        }

        public void UnregisterChild(SelectGroupContext child)
        {
            if (_childGroups.Remove(child)) _onChanged();
        }

        /// <summary>Triggers the owning group's change handler. Used by child groups to
        /// bubble visibility / aggregation changes up the chain.</summary>
        public void NotifyChildrenChanged() => _onChanged();

        public int VisibleDescendantCount
            => _items.Values.Count(i => i.Visible) + _childGroups.Sum(g => g.VisibleDescendantCount);

        /// <summary>Every descendant value across nested groups, excluding disabled items.
        /// Drives both the tri-state aggregation and GroupSelect's select-all toggle when
        /// no search filter is active.</summary>
        public IEnumerable<string> SelectableDescendantValues
            => _items.Values.Where(i => !i.Disabled).Select(i => i.Value)
                .Concat(_childGroups.SelectMany(g => g.SelectableDescendantValues));

        /// <summary>Selectable descendants that also currently pass the search filter. Used
        /// when a search is active so "select all" targets only matches the user can see.</summary>
        public IEnumerable<string> VisibleSelectableDescendantValues
            => _items.Values.Where(i => !i.Disabled && i.Visible).Select(i => i.Value)
                .Concat(_childGroups.SelectMany(g => g.VisibleSelectableDescendantValues));
    }
}

